<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\Shops\ShopOfferCategory;use App\Domain\Shops\ShopOfferVisibility;use App\Domain\WorldCatalog\CatalogStatus;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
final class ShopOfferRequest extends FormRequest{public function authorize(){return true;}public function rules(){return['item_id'=>'required|integer|exists:items,id','category'=>['required',Rule::in(ShopOfferCategory::values())],'quantity'=>['required','regex:/^[1-9][0-9]*$/'],'gold_price'=>['required','regex:/^[1-9][0-9]*$/'],'visibility'=>['required',Rule::in(ShopOfferVisibility::values())],'status'=>['required',Rule::in([CatalogStatus::ACTIVE,CatalogStatus::INACTIVE])],'stock_mode'=>['required',Rule::in(['unlimited','limited'])],'stock_limit'=>['nullable','required_if:stock_mode,limited','regex:/^[1-9][0-9]*$/'],'stock_remaining'=>['nullable','required_if:stock_mode,limited','regex:/^(0|[1-9][0-9]*)$/'],'purchase_limit_per_character'=>['nullable','regex:/^[1-9][0-9]*$/'],'required_character_level'=>['nullable','regex:/^[1-9][0-9]*$/'],'starts_at'=>'nullable|date_format:Y-m-d\TH:i','ends_at'=>'nullable|date_format:Y-m-d\TH:i|after:starts_at','sort_order'=>'required|integer|min:0'];}}
